   337→ */
   338→export async function getStoreData<T = unknown>(
   339→  page: Page,
   340→  storeName: string
   341→): Promise<T | null> {
   342→  // Map test name to actual IndexedDB key
   343→  const actualStoreName = STORE_NAME_MAP[storeName] || storeName;
   344→
   345→  return page.evaluate(async (name) => {
   346→    const dbName = 'neuman-brain-db';
   347→    return new Promise((resolve, reject) => {
   348→      const request = indexedDB.open(dbName);
   349→
   350→      request.onerror = () => reject(request.error);
   351→
   352→      request.onsuccess = () => {
   353→        const db = request.result;
   354→        const transaction = db.transaction('brain-data', 'readonly');
   355→        const store = transaction.objectStore('brain-data');
   356→        const getRequest = store.get(name);
   357→
   358→        getRequest.onsuccess = () => {
   359→          const value = getRequest.result;
   360→          resolve(value ? JSON.parse(value) : null);
   361→        };
   362→
   363→        getRequest.onerror = () => reject(getRequest.error);
   364→      };
   365→    });
   366→  }, actualStoreName);
   367→}
