   373→  page: Page,
   374→  storeName: string,
   375→  data: T
   376→): Promise<void> {
   377→  // Map test name to actual IndexedDB key
   378→  const actualStoreName = STORE_NAME_MAP[storeName] || storeName;
   379→
   380→  // Tests should pass data in Zustand persist format: { state: {...}, version: 0 }
   381→  // This function writes it directly to IndexedDB without modification
   382→  await page.evaluate(
   383→    async ({ name, value }) => {
   384→      const dbName = 'neuman-brain-db';
   385→      return new Promise((resolve, reject) => {
