   391→          const db = request.result;
   392→          const transaction = db.transaction('brain-data', 'readwrite');
   393→          const store = transaction.objectStore('brain-data');
   394→          const putRequest = store.put(JSON.stringify(value), name);
   395→
   396→          putRequest.onsuccess = () => resolve();
   397→          putRequest.onerror = () => reject(putRequest.error);
   398→        };
   399→      });
   400→    },
   401→    { name: actualStoreName, value: data }
   402→  );
   403→}
