   405→/**
   406→ * Check if app has finished loading and IndexedDB is ready
   407→ */
   408→export async function waitForAppLoaded(page: Page): Promise<void> {
   409→  // Wait for main content
   410→  await page.waitForSelector('[role="main"], main, #root', { state: 'visible' });
   411→
   412→  // Wait for IndexedDB to be initialized
   413→  await page.evaluate(async () => {
   414→    return new Promise<void>((resolve) => {
   415→      const checkDB = () => {
   416→        const request = indexedDB.open('neuman-brain-db');
   417→        request.onsuccess = () => {
   418→          request.result.close();
   419→          resolve();
   420→        };
   421→        request.onerror = () => {
   422→          setTimeout(checkDB, 100);
   423→        };
   424→      };
   425→      checkDB();
   426→    });
   427→  });
   428→}
