   431→
   432→/**
   433→ * Reset all ID counters (call in beforeEach)
   434→ */
   435→export function resetTestCounters(): void {
   436→  taskIdCounter = 1;
   437→  eventIdCounter = 1;
   438→  noteIdCounter = 1;
   439→  timeEntryIdCounter = 1;
   440→  ruleIdCounter = 1;
   441→}
   442→
   443→// ==================== DATE HELPERS ====================
   444→
   445→/**
   446→ * Format date to YYYY-M-D (Neuman Brain's canonical format)
   447→ */
   448→export function formatDateKey(date: Date): string {
   449→  return `${date.getFullYear()}-${date.getMonth() + 1}-${date.getDate()}`;
   450→}
   451→
   452→/**
   453→ * Get today's date key
   454→ */
   455→export function getTodayKey(): string {
   456→  return formatDateKey(new Date());
   457→}
   458→
   459→/**
   460→ * Get date N days from now
   461→ */
   462→export function getFutureDateKey(daysFromNow: number): string {
   463→  const date = new Date();
   464→  date.setDate(date.getDate() + daysFromNow);
   465→  return formatDateKey(date);
   466→}
   467→
   468→/**
   469→ * Get date N days ago
   470→ */
   471→export function getPastDateKey(daysAgo: number): string {
   472→  const date = new Date();
   473→  date.setDate(date.getDate() - daysAgo);
   474→  return formatDateKey(date);
   475→}
