     1→/**
     2→ * Notes Editor Component
     3→ *
     4→ * Rich text editor using Lexical
     5→ * Auto-saves changes to Notes store (debounced)
     6→ */
     7→
     8→import React, { useState, useRef, useCallback, useEffect, useMemo } from 'react';
     9→import { LexicalComposer } from '@lexical/react/LexicalComposer';
    10→import { RichTextPlugin } from '@lexical/react/LexicalRichTextPlugin';
    11→import { ContentEditable } from '@lexical/react/LexicalContentEditable';
    12→import { HistoryPlugin } from '@lexical/react/LexicalHistoryPlugin';
    13→import { OnChangePlugin } from '@lexical/react/LexicalOnChangePlugin';
    14→import { useLexicalComposerContext } from '@lexical/react/LexicalComposerContext';
    15→import { LexicalErrorBoundary } from '@lexical/react/LexicalErrorBoundary';
    16→import { HeadingNode, QuoteNode } from '@lexical/rich-text';
    17→import { ListNode, ListItemNode } from '@lexical/list';
    18→import { CodeNode, CodeHighlightNode } from '@lexical/code';
    19→import { LinkNode } from '@lexical/link';
    20→import { TableNode, TableCellNode, TableRowNode } from '@lexical/table';
    21→import { ListPlugin } from '@lexical/react/LexicalListPlugin';
    22→import { TablePlugin } from '@lexical/react/LexicalTablePlugin';
    23→import { MarkdownShortcutPlugin } from '@lexical/react/LexicalMarkdownShortcutPlugin';
    24→import { AutoLinkPlugin } from '@lexical/react/LexicalAutoLinkPlugin';
    25→import { AutoLinkNode } from '@lexical/link';
    26→import { TRANSFORMERS } from '@lexical/markdown';
    27→import {
    28→  $getRoot,
    29→  $getSelection,
    30→  FORMAT_TEXT_COMMAND,
    31→  $isRangeSelection,
    32→  $createParagraphNode,
    33→  UNDO_COMMAND,
    34→  REDO_COMMAND,
    35→  $isParagraphNode
    36→} from 'lexical';
    37→import type { EditorState } from 'lexical';
    38→import {
    39→  registerRichText,
    40→  $createHeadingNode,
    41→  $createQuoteNode,
    42→  $isHeadingNode,
    43→  $isQuoteNode
    44→} from '@lexical/rich-text';
    45→import type { HeadingTagType } from '@lexical/rich-text';
    46→import {
    47→  INSERT_UNORDERED_LIST_COMMAND,
    48→  INSERT_ORDERED_LIST_COMMAND,
    49→  $isListNode
    50→} from '@lexical/list';
    51→
    52→// URL matcher for AutoLinkPlugin
    53→const URL_MATCHER =
    54→  /((https?:\/\/(www\.)?)|(www\.))[-a-zA-Z0-9@:%._+~#=]{1,256}\.[a-zA-Z0-9()]{1,6}\b([-a-zA-Z0-9()@:%_+.~#?&//=]*)/;
    55→
    56→const MATCHERS = [
    57→  (text: string) => {
    58→    const match = URL_MATCHER.exec(text);
    59→    if (match === null) {
    60→      return null;
    61→    }
    62→    const fullMatch = match[0];
    63→    return {
    64→      index: match.index,
    65→      length: fullMatch.length,
    66→      text: fullMatch,
    67→      url: fullMatch.startsWith('http') ? fullMatch : `https://${fullMatch}`,
    68→    };
    69→  },
    70→];
    71→import { motion } from 'framer-motion';
    72→import { useNotesStore } from '../stores/useNotesStore';
    73→import { useSettingsStore } from '../stores/useSettingsStore';
    74→import { TagPicker } from '../components/TagPicker';
    75→import { CustomFieldEditor } from '../components/CustomFieldEditor';
    76→import { NOTE_CONSTANTS } from '../types/notes';
    77→import { ImageNode, $createImageNode } from './NotesEditor/ImageNode';
    78→import { indexedDBService } from '../services/indexedDB';
    79→import { BacklinksPanel } from '../components/BacklinksPanel';
    80→
    81→/**
    82→ * Keyboard Shortcuts Plugin
    83→ * Registers rich text keyboard shortcuts (Cmd+B, Cmd+I, Cmd+U)
    84→ */
    85→const KeyboardShortcutsPlugin: React.FC = () => {
    86→  const [editor] = useLexicalComposerContext();
    87→
    88→  useEffect(() => {
    89→    return registerRichText(editor);
    90→  }, [editor]);
    91→
    92→  return null;
    93→};
    94→
    95→/**
    96→ * Word Count Plugin
    97→ * Tracks word and character count from editor content
    98→ */
    99→const WordCountPlugin: React.FC<{ onUpdate: (words: number, chars: number) => void }> = ({ onUpdate }) => {
   100→  const [editor] = useLexicalComposerContext();
   101→
   102→  useEffect(() => {
   103→    return editor.registerTextContentListener((textContent) => {
   104→      const words = textContent.trim().split(/\s+/).filter(Boolean).length;
   105→      const chars = textContent.length;
   106→      onUpdate(words, chars);
   107→    });
   108→  }, [editor, onUpdate]);
   109→
   110→  return null;
   111→};
   112→
   113→/**
   114→ * Image Upload Plugin
   115→ * Handles drag-and-drop and paste events for images
   116→ */
   117→const ImageUploadPlugin: React.FC<{ noteId: string }> = ({ noteId }) => {
   118→  const [editor] = useLexicalComposerContext();
   119→  const [isDragging, setIsDragging] = useState(false);
   120→
   121→  const uploadImage = useCallback(async (file: File) => {
   122→    try {
   123→      // Store image in IndexedDB with compression
   124→      const imageId = await indexedDBService.storeImage(noteId, file);
   125→
   126→      // Retrieve compressed blob
   127→      const blob = await indexedDBService.getImage(imageId);
   128→      if (!blob) {
   129→        console.error('Failed to retrieve stored image');
   130→        return;
   131→      }
   132→
   133→      // Create blob URL for rendering
   134→      const blobUrl = URL.createObjectURL(blob);
   135→
   136→      // Insert image node into editor
   137→      editor.update(() => {
   138→        const selection = $getSelection();
   139→        if ($isRangeSelection(selection)) {
   140→          const imageNode = $createImageNode({
   141→            altText: file.name,
   142→            src: blobUrl,
   143→            imageId: imageId,
   144→          });
   145→          selection.insertNodes([imageNode]);
   146→        }
   147→      });
   148→
   149→      console.log(`✅ Image uploaded: ${imageId} (${file.name})`);
   150→    } catch (error) {
   151→      console.error('Failed to upload image:', error);
   152→    }
   153→  }, [editor, noteId]);
   154→
   155→  useEffect(() => {
   156→    const editorElement = editor.getRootElement();
   157→    if (!editorElement) return;
   158→
   159→    // Drag and drop handlers
   160→    const handleDragEnter = (e: DragEvent) => {
   161→      e.preventDefault();
   162→      e.stopPropagation();
   163→      if (e.dataTransfer?.types.includes('Files')) {
   164→        setIsDragging(true);
   165→      }
   166→    };
   167→
   168→    const handleDragOver = (e: DragEvent) => {
   169→      e.preventDefault();
   170→      e.stopPropagation();
   171→    };
   172→
   173→    const handleDragLeave = (e: DragEvent) => {
   174→      e.preventDefault();
   175→      e.stopPropagation();
   176→      // Only hide if leaving the editor entirely
   177→      if (e.target === editorElement) {
   178→        setIsDragging(false);
   179→      }
   180→    };
   181→
   182→    const handleDrop = async (e: DragEvent) => {
   183→      e.preventDefault();
   184→      e.stopPropagation();
   185→      setIsDragging(false);
   186→
   187→      const files = Array.from(e.dataTransfer?.files || []);
   188→      const imageFiles = files.filter(file => file.type.startsWith('image/'));
   189→
   190→      for (const file of imageFiles) {
   191→        await uploadImage(file);
   192→      }
   193→    };
   194→
   195→    // Paste handler
   196→    const handlePaste = async (e: ClipboardEvent) => {
   197→      const items = Array.from(e.clipboardData?.items || []);
   198→      const imageItems = items.filter(item => item.type.startsWith('image/'));
   199→
   200→      if (imageItems.length > 0) {
   201→        e.preventDefault();
   202→
   203→        for (const item of imageItems) {
   204→          const file = item.getAsFile();
   205→          if (file) {
   206→            await uploadImage(file);
   207→          }
   208→        }
   209→      }
   210→    };
   211→
   212→    editorElement.addEventListener('dragenter', handleDragEnter);
   213→    editorElement.addEventListener('dragover', handleDragOver);
   214→    editorElement.addEventListener('dragleave', handleDragLeave);
   215→    editorElement.addEventListener('drop', handleDrop);
   216→    editorElement.addEventListener('paste', handlePaste);
   217→
   218→    return () => {
   219→      editorElement.removeEventListener('dragenter', handleDragEnter);
   220→      editorElement.removeEventListener('dragover', handleDragOver);
   221→      editorElement.removeEventListener('dragleave', handleDragLeave);
   222→      editorElement.removeEventListener('drop', handleDrop);
   223→      editorElement.removeEventListener('paste', handlePaste);
   224→    };
   225→  }, [editor, uploadImage]);
   226→
   227→  // Drag overlay
   228→  if (isDragging) {
   229→    return (
   230→      <div className="absolute inset-0 z-50 bg-accent-blue/10 border-2 border-dashed border-accent-blue rounded-lg flex items-center justify-center pointer-events-none">
   231→        <div className="bg-surface-light dark:bg-surface-dark px-6 py-4 rounded-lg shadow-elevated">
   232→          <p className="text-accent-blue text-lg font-semibold">Drop image here</p>
   233→        </div>
   234→      </div>
   235→    );
   236→  }
   237→
   238→  return null;
   239→};
   240→
   241→/**
   242→ * Slash Command Plugin
   243→ * Detects '/' and shows command menu
   244→ */
   245→const SlashCommandPlugin: React.FC = () => {
   246→  const [editor] = useLexicalComposerContext();
   247→  const [showMenu, setShowMenu] = useState(false);
   248→  const [query, setQuery] = useState('');
   249→  const [menuPosition, setMenuPosition] = useState({ top: 0, left: 0 });
   250→
   251→  const commands = [
   252→    { label: 'Heading 1', icon: 'H1', action: () => {
   253→      editor.update(() => {
   254→        const selection = $getSelection();
   255→        if (selection) {
   256→          // Convert to heading - will implement with format commands
   257→          console.log('Heading 1');
   258→        }
   259→      });
   260→    }},
   261→    { label: 'Heading 2', icon: 'H2', action: () => console.log('Heading 2') },
   262→    { label: 'Heading 3', icon: 'H3', action: () => console.log('Heading 3') },
   263→    { label: 'Bullet List', icon: '•', action: () => console.log('Bullet List') },
   264→    { label: 'Numbered List', icon: '1.', action: () => console.log('Numbered List') },
   265→    { label: 'Code Block', icon: '</>', action: () => console.log('Code Block') },
   266→    { label: 'Quote', icon: '"', action: () => console.log('Quote') },
   267→  ];
   268→
   269→  const filteredCommands = commands.filter(cmd =>
   270→    cmd.label.toLowerCase().includes(query.toLowerCase())
   271→  );
   272→
   273→  useEffect(() => {
   274→    return editor.registerUpdateListener(({ editorState }) => {
   275→      editorState.read(() => {
   276→        const selection = $getSelection();
   277→        if (!selection) {
   278→          setShowMenu(false);
   279→          return;
   280→        }
   281→
   282→        const text = selection.getTextContent();
   283→        if (text.startsWith('/')) {
   284→          setQuery(text.slice(1));
   285→          setShowMenu(true);
   286→
   287→          // Get cursor position for menu placement
   288→          const nativeSelection = window.getSelection();
   289→          if (nativeSelection && nativeSelection.rangeCount > 0) {
   290→            const range = nativeSelection.getRangeAt(0);
   291→            const rect = range.getBoundingClientRect();
   292→            setMenuPosition({
   293→              top: rect.bottom + window.scrollY + 5,
   294→              left: rect.left + window.scrollX,
   295→            });
   296→          }
   297→        } else {
   298→          setShowMenu(false);
   299→        }
   300→      });
   301→    });
   302→  }, [editor]);
   303→
   304→  if (!showMenu || filteredCommands.length === 0) {
   305→    return null;
   306→  }
   307→
   308→  return (
   309→    <div
   310→      style={{
   311→        position: 'absolute',
   312→        top: `${menuPosition.top}px`,
   313→        left: `${menuPosition.left}px`,
   314→        zIndex: 1000,
   315→      }}
   316→      className="bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-lg shadow-lg py-2 min-w-[200px]"
   317→    >
   318→      {filteredCommands.map((cmd, index) => (
   319→        <button
   320→          key={index}
   321→          onClick={() => {
   322→            cmd.action();
   323→            setShowMenu(false);
   324→          }}
   325→          className="w-full px-4 py-2 text-left hover:bg-surface-light dark:hover:bg-neutral-800 transition-colors flex items-center gap-3"
   326→        >
   327→          <span className="text-text-light-secondary dark:text-text-dark-secondary font-mono">
   328→            {cmd.icon}
   329→          </span>
   330→          <span className="text-text-light-primary dark:text-text-dark-primary">
   331→            {cmd.label}
   332→          </span>
   333→        </button>
   334→      ))}
   335→    </div>
   336→  );
   337→};
   338→
   339→/**
   340→ * Editor Toolbar Component
   341→ */
   342→const EditorToolbar: React.FC<{ wordCount: number; charCount: number; noteId: string }> = ({ wordCount, charCount, noteId }) => {
   343→  const [editor] = useLexicalComposerContext();
   344→  const fileInputRef = useRef<HTMLInputElement>(null);
   345→
   346→  const formatText = (format: 'bold' | 'italic' | 'underline' | 'strikethrough' | 'code') => {
   347→    editor.dispatchCommand(FORMAT_TEXT_COMMAND, format);
   348→  };
   349→
   350→  const formatHeading = (headingSize: HeadingTagType) => {
   351→    editor.update(() => {
   352→      const selection = $getSelection();
   353→      if ($isRangeSelection(selection)) {
   354→        const anchorNode = selection.anchor.getNode();
   355→        const element = anchorNode.getKey() === 'root'
   356→          ? anchorNode
   357→          : anchorNode.getTopLevelElementOrThrow();
   358→
   359→        if ($isHeadingNode(element) && element.getTag() === headingSize) {
   360→          // If already this heading, convert to paragraph
   361→          const paragraph = $createParagraphNode();
   362→          element.replace(paragraph, true);
   363→        } else {
   364→          // Convert to heading
   365→          const heading = $createHeadingNode(headingSize);
   366→          element.replace(heading, true);
   367→        }
   368→      }
   369→    });
   370→  };
   371→
   372→  const formatParagraph = () => {
   373→    editor.update(() => {
   374→      const selection = $getSelection();
   375→      if ($isRangeSelection(selection)) {
   376→        const anchorNode = selection.anchor.getNode();
   377→        const element = anchorNode.getKey() === 'root'
   378→          ? anchorNode
   379→          : anchorNode.getTopLevelElementOrThrow();
   380→
   381→        if (!$isParagraphNode(element) && !$isListNode(element)) {
   382→          const paragraph = $createParagraphNode();
   383→          element.replace(paragraph, true);
   384→        }
   385→      }
   386→    });
   387→  };
   388→
   389→  const formatQuote = () => {
   390→    editor.update(() => {
   391→      const selection = $getSelection();
   392→      if ($isRangeSelection(selection)) {
   393→        const anchorNode = selection.anchor.getNode();
   394→        const element = anchorNode.getKey() === 'root'
   395→          ? anchorNode
   396→          : anchorNode.getTopLevelElementOrThrow();
   397→
   398→        if ($isQuoteNode(element)) {
   399→          // If already a quote, convert to paragraph
   400→          const paragraph = $createParagraphNode();
   401→          element.replace(paragraph, true);
   402→        } else if (!$isListNode(element)) {
   403→          const quote = $createQuoteNode();
   404→          element.replace(quote, true);
   405→        }
   406→      }
   407→    });
   408→  };
   409→
   410→  const formatBulletList = () => {
   411→    editor.dispatchCommand(INSERT_UNORDERED_LIST_COMMAND, undefined);
   412→  };
   413→
   414→  const formatNumberedList = () => {
   415→    editor.dispatchCommand(INSERT_ORDERED_LIST_COMMAND, undefined);
   416→  };
   417→
   418→  const undo = () => {
   419→    editor.dispatchCommand(UNDO_COMMAND, undefined);
   420→  };
   421→
   422→  const redo = () => {
   423→    editor.dispatchCommand(REDO_COMMAND, undefined);
   424→  };
   425→
   426→  const handleImageUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
   427→    const file = event.target.files?.[0];
   428→    if (!file) return;
   429→
   430→    // Reset input immediately
   431→    if (fileInputRef.current) {
   432→      fileInputRef.current.value = '';
   433→    }
   434→
   435→    try {
   436→      // Store image in IndexedDB with compression
   437→      const imageId = await indexedDBService.storeImage(noteId, file);
   438→
   439→      // Retrieve compressed blob
   440→      const blob = await indexedDBService.getImage(imageId);
   441→      if (!blob) {
   442→        console.error('Failed to retrieve stored image');
   443→        return;
   444→      }
   445→
   446→      // Create blob URL for rendering
   447→      const blobUrl = URL.createObjectURL(blob);
   448→
   449→      // Insert image node into editor
   450→      editor.update(() => {
   451→        const selection = $getSelection();
   452→        if ($isRangeSelection(selection)) {
   453→          const imageNode = $createImageNode({
   454→            altText: file.name,
   455→            src: blobUrl,
   456→            imageId: imageId,
   457→          });
   458→          selection.insertNodes([imageNode]);
   459→        }
   460→      });
   461→
   462→      console.log(`✅ Image uploaded: ${imageId} (${file.name})`);
   463→    } catch (error) {
   464→      console.error('Failed to upload image:', error);
   465→      alert(`Failed to upload image: ${error instanceof Error ? error.message : 'Unknown error'}\n\nPlease check:\n• File size (max 5MB)\n• Storage quota (Settings > Storage)`);
   466→    }
   467→  };
   468→
   469→  const btnClass = "p-2 hover:bg-surface-light-elevated dark:hover:bg-neutral-800 rounded transition-all duration-standard text-text-light-primary dark:text-text-dark-primary";
   470→  const dividerClass = "w-px h-6 bg-border-light dark:bg-border-dark";
   471→
   472→  return (
   473→    <div className="border-b border-border-light dark:border-border-dark bg-surface-light dark:bg-surface-dark-elevated p-3 flex items-center gap-2 flex-wrap">
   474→      {/* Undo/Redo */}
   475→      <button onClick={undo} className={btnClass} title="Undo (Cmd+Z)">
   476→        ↶
   477→      </button>
   478→      <button onClick={redo} className={btnClass} title="Redo (Cmd+Shift+Z)">
   479→        ↷
   480→      </button>
   481→
   482→      <div className={dividerClass} />
   483→
   484→      {/* Text Format */}
   485→      <button onClick={() => formatText('bold')} className={btnClass} title="Bold (Cmd+B)">
   486→        <span className="font-bold">B</span>
   487→      </button>
   488→      <button onClick={() => formatText('italic')} className={btnClass} title="Italic (Cmd+I)">
   489→        <span className="italic">I</span>
   490→      </button>
   491→      <button onClick={() => formatText('underline')} className={btnClass} title="Underline (Cmd+U)">
   492→        <span className="underline">U</span>
   493→      </button>
   494→      <button onClick={() => formatText('strikethrough')} className={btnClass} title="Strikethrough">
   495→        <span className="line-through">S</span>
   496→      </button>
   497→      <button onClick={() => formatText('code')} className={btnClass} title="Code">
   498→        <span className="font-mono text-sm">&lt;/&gt;</span>
   499→      </button>
