   504→      <button onClick={() => formatHeading('h1')} className={btnClass} title="Heading 1">
   505→        <span className="font-bold text-lg">H1</span>
   506→      </button>
   507→      <button onClick={() => formatHeading('h2')} className={btnClass} title="Heading 2">
   508→        <span className="font-bold">H2</span>
   509→      </button>
   510→      <button onClick={() => formatHeading('h3')} className={btnClass} title="Heading 3">
   511→        <span className="font-bold text-sm">H3</span>
   512→      </button>
