   553→      </span>
   554→    </div>
   555→  );
   556→};
   557→
   558→/**
   559→ * Auto-save Plugin
   560→ * Debounces editor changes and saves to store
   561→ */
   562→const AutoSavePlugin: React.FC<{ noteId: string }> = ({ noteId }) => {
   563→  const [isSaving, setIsSaving] = useState(false);
   564→  const updateNote = useNotesStore((state) => state.updateNote);
   565→
   566→  // Track timeout ID and last saved content to prevent redundant saves
   567→  const timeoutIdRef = useRef<ReturnType<typeof setTimeout> | null>(null);
   568→  const lastContentRef = useRef<string>('');
   569→  const lastTextRef = useRef<string>('');
   570→
   571→  const handleChange = useCallback((editorState: EditorState) => {
   572→    // Extract plain text for search
   573→    editorState.read(() => {
   574→      const root = $getRoot();
   575→      const contentText = root.getTextContent();
   576→      const contentJson = JSON.stringify(editorState.toJSON());
   577→
   578→      // Skip save if content hasn't actually changed
   579→      if (contentJson === lastContentRef.current && contentText === lastTextRef.current) {
   580→        return;
   581→      }
   582→
   583→      // Clear previous timeout to implement proper debouncing
   584→      if (timeoutIdRef.current) {
   585→        clearTimeout(timeoutIdRef.current);
   586→      }
   587→
   588→      // Debounced save with error handling
   589→      timeoutIdRef.current = setTimeout(() => {
   590→        setIsSaving(true);
   591→
   592→        try {
   593→          // Zustand is synchronous, but IndexedDB persistence could fail
   594→          updateNote(noteId, {
   595→            content: contentJson,
   596→            contentText,
   597→          });
   598→
   599→          // Update refs with saved content
   600→          lastContentRef.current = contentJson;
   601→          lastTextRef.current = contentText;
   602→
   603→          // Reset saving state after a brief delay
   604→          setTimeout(() => setIsSaving(false), 300);
   605→        } catch (error) {
   606→          console.error('❌ Failed to save note:', error);
   607→          setIsSaving(false);
   608→          // Error will be handled by IndexedDB quota monitoring system
   609→          // User will be alerted if quota is exceeded via Settings page
   610→        }
   611→      }, NOTE_CONSTANTS.AUTOSAVE_DEBOUNCE_MS);
   612→    });
   613→  }, [noteId, updateNote]);
   614→
   615→  // Cleanup timeout on unmount
   616→  useEffect(() => {
   617→    return () => {
   618→      if (timeoutIdRef.current) {
   619→        clearTimeout(timeoutIdRef.current);
   620→      }
   621→    };
   622→  }, []);
   623→
   624→  return (
   625→    <>
   626→      <OnChangePlugin onChange={handleChange} />
   627→      {isSaving && (
   628→        <div className="absolute top-2 right-2 text-xs text-text-light-secondary dark:text-text-dark-secondary">
   629→          Saving...
   630→        </div>
   631→      )}
   632→    </>
   633→  );
   634→};
   635→
   636→/**
   637→ * Lexical Editor Configuration
   638→ */
   639→const getEditorConfig = (initialContent?: string) => ({
   640→  namespace: 'NotesEditor',
   641→  editorState: initialContent || null,
   642→  theme: {
   643→    root: 'editor-root',
   644→    paragraph: 'editor-paragraph',
   645→    text: {
   646→      bold: 'font-bold',
   647→      italic: 'italic',
   648→      underline: 'underline',
   649→      strikethrough: 'line-through',
   650→      code: 'font-mono bg-neutral-100 dark:bg-neutral-800 px-1 rounded',
   651→    },
   652→    heading: {
   653→      h1: 'text-4xl font-bold mt-6 mb-4',
   654→      h2: 'text-3xl font-bold mt-5 mb-3',
   655→      h3: 'text-2xl font-bold mt-4 mb-2',
   656→    },
   657→    list: {
   658→      ul: 'list-disc list-inside my-4',
   659→      ol: 'list-decimal list-inside my-4',
   660→      listitem: 'my-1',
   661→    },
   662→    quote: 'border-l-4 border-border-light dark:border-border-dark pl-4 italic my-4',
   663→    code: 'bg-neutral-900 text-neutral-100 p-4 rounded-lg font-mono text-sm my-4 overflow-x-auto',
   664→    link: 'text-primary-cyan hover:underline',
   665→  },
   666→  nodes: [
   667→    HeadingNode,
   668→    QuoteNode,
   669→    ListNode,
   670→    ListItemNode,
   671→    CodeNode,
   672→    CodeHighlightNode,
   673→    LinkNode,
   674→    AutoLinkNode,
   675→    TableNode,
   676→    TableCellNode,
   677→    TableRowNode,
   678→    ImageNode,
   679→  ],
   680→  onError: (error: Error) => {
   681→    console.error('Lexical error:', error);
   682→  },
   683→});
   684→
   685→/**
   686→ * Notes Editor Props
   687→ */
   688→interface NotesEditorProps {
   689→  noteId: string;
   690→}
   691→
   692→/**
   693→ * Tags Input Component
   694→ * Simple tag management with pills
   695→ */
   696→const TagsInput: React.FC<{ noteId: string; tags: string[] }> = ({ noteId, tags }) => {
   697→  const addTag = useNotesStore((state) => state.addTag);
   698→  const removeTag = useNotesStore((state) => state.removeTag);
   699→
   700→  const handleAddTag = (tag: string) => {
   701→    addTag(noteId, tag);
   702→  };
   703→
   704→  const handleRemoveTag = (tag: string) => {
   705→    removeTag(noteId, tag);
   706→  };
   707→
   708→  return (
   709→    <div className="mt-3">
   710→      <TagPicker
   711→        selectedTags={tags}
   712→        onAddTag={handleAddTag}
   713→        onRemoveTag={handleRemoveTag}
   714→        maxTags={NOTE_CONSTANTS.MAX_TAGS}
   715→      />
   716→    </div>
   717→  );
   718→};
   719→
   720→/**
   721→ * Custom Fields Section Component
   722→ * Renders custom fields defined in settings for notes
   723→ */
   724→const NoteCustomFields: React.FC<{ noteId: string; note: ReturnType<typeof useNotesStore.getState>['notes'][number] }> = ({ noteId, note }) => {
   725→  const { customFieldDefinitions } = useSettingsStore();
   726→  const noteFields = customFieldDefinitions.notes;
   727→
   728→  if (noteFields.length === 0) return null;
   729→
   730→  return (
   731→    <div className="mt-4 space-y-3">
   732→      <div className="text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary">
   733→        Custom Fields
   734→      </div>
   735→      {noteFields.map((field) => {
   736→        const currentValue = note.customFields?.[field.id];
   737→
   738→        return (
   739→          <div key={field.id}>
   740→            <label className="block text-xs font-medium text-text-light-primary dark:text-text-dark-primary mb-1">
   741→              {field.name}
   742→              {field.required && (
   743→                <span className="text-status-error-text dark:text-status-error-text-dark ml-1">*</span>
   744→              )}
   745→            </label>
   746→            {field.description && (
   747→              <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary mb-1">
   748→                {field.description}
   749→              </p>
   750→            )}
   751→            <CustomFieldEditor
   752→              field={field}
   753→              value={currentValue}
   754→              onChange={(value) => {
   755→                const updatedCustomFields = {
   756→                  ...note.customFields,
   757→                  [field.id]: value,
   758→                };
   759→                useNotesStore.getState().updateNote(noteId, { customFields: updatedCustomFields });
   760→              }}
   761→            />
   762→          </div>
   763→        );
   764→      })}
   765→    </div>
   766→  );
   767→};
   768→
   769→/**
   770→ * Notes Editor Component
   771→ */
   772→export const NotesEditor: React.FC<NotesEditorProps> = ({ noteId }) => {
   773→  const note = useNotesStore((state) => state.getNote(noteId));
   774→  const [wordCount, setWordCount] = useState(0);
   775→  const [charCount, setCharCount] = useState(0);
   776→
   777→  // Memoize editor config to prevent Lexical re-initialization
   778→  // Only recreate when noteId changes, not when content changes
   779→  const editorConfig = useMemo(
   780→    () => getEditorConfig(note?.content),
   781→    [noteId] // Key on noteId only, not note.content
   782→  );
   783→
   784→  const handleWordCountUpdate = useCallback((words: number, chars: number) => {
   785→    setWordCount(words);
   786→    setCharCount(chars);
   787→  }, []);
   788→
   789→  if (!note) {
   790→    return (
   791→      <div className="h-full flex items-center justify-center text-text-light-secondary dark:text-text-dark-secondary">
   792→        Note not found
   793→      </div>
   794→    );
   795→  }
   796→
   797→  return (
   798→    <motion.div
   799→      initial={{ opacity: 0 }}
   800→      animate={{ opacity: 1 }}
   801→      transition={{ duration: 0.2 }}
   802→      className="h-full flex flex-col bg-surface-light dark:bg-surface-dark"
   803→    >
   804→      {/* Note Title & Tags */}
   805→      <div className="border-b border-border-light dark:border-border-dark px-6 py-4 flex-shrink-0">
   806→        <input
   807→          type="text"
   808→          value={note.title}
   809→          onChange={(e) =>
   810→            useNotesStore.getState().updateNote(noteId, { title: e.target.value })
   811→          }
   812→          placeholder="Untitled Note"
   813→          className="w-full text-3xl font-bold bg-transparent border-none outline-none text-text-light-primary dark:text-text-dark-primary placeholder-text-light-secondary dark:placeholder-text-dark-secondary"
   814→        />
   815→        <TagsInput noteId={noteId} tags={note.tags} />
   816→
   817→        {/* Custom Fields (P2 #3) */}
   818→        <NoteCustomFields noteId={noteId} note={note} />
   819→      </div>
   820→
   821→      {/* Lexical Editor */}
   822→      <LexicalComposer key={noteId} initialConfig={editorConfig}>
   823→        <div className="flex-1 flex flex-col relative overflow-hidden shadow-card">
   824→          {/* Toolbar */}
   825→          <div className="flex-shrink-0">
   826→            <EditorToolbar wordCount={wordCount} charCount={charCount} noteId={noteId} />
   827→          </div>
   828→
   829→          {/* Editor Content */}
   830→          <div className="flex-1 overflow-y-auto">
   831→            <div className="w-full h-full px-8 py-6">
   832→              <div className="border border-border-light dark:border-border-dark rounded-lg p-3 h-full bg-surface-light dark:bg-surface-dark">
   833→                <RichTextPlugin
   834→                  contentEditable={
   835→                    <ContentEditable className="editor-content outline-none w-full h-full text-text-light-primary dark:text-text-dark-primary" />
