   181→/**
   182→ * Folder Sidebar Component (Simplified for MVP)
   183→ */
   184→const FolderSidebar: React.FC<{
   185→  activeTags: string[];
   186→  onAddTag: (tag: string) => void;
   187→  onRemoveTag: (tag: string) => void;
   188→  onClearAllTags: () => void;
   189→  onOpenTagManager: () => void;
   190→}> = ({ activeTags, onAddTag, onRemoveTag, onClearAllTags, onOpenTagManager }) => {
   191→  // Get raw folders object (stable reference unless folders change)
   192→  const foldersObj = useFoldersStore((state) => state.folders);
   193→  const activeFolderId = useFoldersStore((state) => state.activeFolderId);
   194→  const setActiveFolder = useFoldersStore((state) => state.setActiveFolder);
   195→  const createFolder = useFoldersStore((state) => state.createFolder);
   196→  const deleteFolder = useFoldersStore((state) => state.deleteFolder);
   197→  const updateFolder = useFoldersStore((state) => state.updateFolder);
   198→  const notesObj = useNotesStore((state) => state.notes);
   199→  const searchNotes = useNotesStore((state) => state.searchNotes);
   200→
   201→  // Dialog state
   202→  const [deleteDialogOpen, setDeleteDialogOpen] = useState(false);
   203→  const [renameDialogOpen, setRenameDialogOpen] = useState(false);
   204→  const [selectedFolderId, setSelectedFolderId] = useState<string | null>(null);
   205→  const [selectedFolderName, setSelectedFolderName] = useState('');
   206→
   207→  // Search state
   208→  const [searchQuery, setSearchQuery] = useState('');
   209→  const searchInputRef = useRef<HTMLInputElement>(null);
   210→
   211→  // Keyboard shortcut for search (Cmd+K)
   212→  useEffect(() => {
   213→    const handleKeyDown = (e: KeyboardEvent) => {
   214→      if ((e.metaKey || e.ctrlKey) && e.key === 'k') {
   215→        e.preventDefault();
   216→        searchInputRef.current?.focus();
   217→      }
   218→    };
   219→
   220→    window.addEventListener('keydown', handleKeyDown);
   221→    return () => window.removeEventListener('keydown', handleKeyDown);
   222→  }, []);
   223→
   224→  // Get tree structure for nested folders
   225→  const getTree = useFoldersStore((state) => state.getTree);
   226→  const toggleExpanded = useFoldersStore((state) => state.toggleExpanded);
   227→  const expandedFolderIds = useFoldersStore((state) => state.expandedFolderIds);
   228→
   229→  const folderTree = useMemo(() => getTree(), [foldersObj, getTree]);
   230→
   231→  // Get note count for a folder
   232→  const getFolderNoteCount = (folderId: string) => {
   233→    return Object.values(notesObj).filter(note => note.folderId === folderId).length;
   234→  };
   235→
   236→  // Handle folder deletion
   237→  const handleDeleteFolder = (folderId: string, folderName: string) => {
   238→    setSelectedFolderId(folderId);
   239→    setSelectedFolderName(folderName);
   240→    setDeleteDialogOpen(true);
   241→  };
   242→
   243→  const confirmDeleteFolder = () => {
   244→    if (!selectedFolderId) return;
   245→
   246→    // Save folder and notes for undo
   247→    const folderToDelete = foldersObj[selectedFolderId];
   248→    if (!folderToDelete) {
   249→      log.warn('Folder not found', { folderId: selectedFolderId });
   250→      return;
   251→    }
   252→
   253→    const notesToDelete = Object.values(notesObj).filter(note => note.folderId === selectedFolderId);
   254→    const noteCount = notesToDelete.length;
   255→
   256→    // Delete all notes in this folder (without undo since folder undo will handle it)
   257→    // We need to temporarily bypass the undo system for individual notes
   258→    notesToDelete.forEach(note => {
   259→      // Call the store action directly without triggering undo
   260→      useNotesStore.setState((state) => {
   261→        const { [note.id]: deleted, ...remainingNotes } = state.notes;
   262→        return {
   263→          notes: remainingNotes,
   264→          activeNoteId: state.activeNoteId === note.id ? null : state.activeNoteId,
   265→        };
   266→      });
   267→    });
   268→
   269→    // Delete the folder
   270→    deleteFolder(selectedFolderId);
   271→
   272→    log.info(`Folder "${folderToDelete.name}" deleted`, { noteCount });
   273→
   274→    // Add undo action to restore folder AND notes
   275→    useUndoStore.getState().addUndoAction(
   276→      `Folder "${folderToDelete.name}" and ${noteCount} note(s) deleted`,
   277→      () => {
   278→        // Restore the folder
   279→        useFoldersStore.setState((state) => ({
   280→          folders: {
   281→            ...state.folders,
   282→            [folderToDelete.id]: folderToDelete,
   283→          },
   284→        }));
   285→
   286→        // Restore all notes
   287→        useNotesStore.setState((state) => {
   288→          const restoredNotes = { ...state.notes };
   289→          notesToDelete.forEach(note => {
   290→            restoredNotes[note.id] = note;
   291→          });
   292→          return {
   293→            notes: restoredNotes,
   294→          };
   295→        });
   296→
   297→        log.info(`Folder "${folderToDelete.name}" and ${noteCount} note(s) restored (undo)`);
   298→      }
   299→    );
   300→  };
   301→
   302→  // Handle folder rename
   303→  const handleRenameFolder = (folderId: string, currentName: string) => {
   304→    setSelectedFolderId(folderId);
   305→    setSelectedFolderName(currentName);
   306→    setRenameDialogOpen(true);
   307→  };
   308→
   309→  const confirmRenameFolder = (newName: string) => {
   310→    if (!selectedFolderId || !newName.trim()) return;
   311→    updateFolder(selectedFolderId, { name: newName.trim() });
   312→  };
   313→
   314→  return (
   315→    <div className="p-4 flex flex-col max-h-[40%] overflow-hidden border-b border-border-light dark:border-border-dark">
   316→      {/* Folders header */}
   317→      <div className="flex items-center justify-between mb-4 flex-shrink-0">
