   331→          type="text"
   332→          placeholder="Search notes... (Cmd+K)"
   333→          className="w-full px-3 py-2 text-sm border border-border-light dark:border-border-dark rounded-lg
   334→                     bg-surface-light dark:bg-surface-dark
   335→                     text-text-light-primary dark:text-text-dark-primary
   336→                     placeholder-text-light-secondary dark:placeholder-text-dark-secondary
   337→                     focus:outline-none focus:ring-2 focus:ring-accent-blue transition-all"
   338→          value={searchQuery}
   339→          onChange={(e) => setSearchQuery(e.target.value)}
   340→          ref={searchInputRef}
   341→        />
   342→      </div>
   343→
   344→      {/* All Notes (root level) */}
   345→      {!searchQuery.trim() && (
   346→        <button
   347→          onClick={() => setActiveFolder(null)}
   348→          className={`w-full text-left px-3 h-8 rounded-lg transition-colors mb-1 flex-shrink-0 flex items-center gap-2 text-base ${
   349→            activeFolderId === null
   350→              ? 'bg-surface-light-elevated dark:bg-surface-dark-elevated text-text-light-primary dark:text-text-dark-primary font-medium'
   351→              : 'hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated text-text-light-secondary dark:text-text-dark-secondary'
   352→          }`}
   353→        >
   354→          <FolderOpen className="w-4 h-4" />
   355→          All Notes
   356→        </button>
   357→      )}
   358→
   359→      {/* Search Results OR Folder list */}
   360→      {searchQuery.trim() ? (
   361→        /* Search Results */
   362→        <div className="px-3 overflow-y-auto flex-1">
   363→          <h3 className="text-sm font-semibold text-text-light-secondary dark:text-text-dark-secondary mb-2">
   364→            {searchNotes(searchQuery).length} results for "{searchQuery}"
   365→          </h3>
   366→          <div className="space-y-2">
   367→            {searchNotes(searchQuery).map((note) => (
   368→              <div
   369→                key={note.id}
   370→                onClick={() => {
   371→                  setSearchQuery(''); // Clear search
   372→                  // Note will be selected via the NotesList component
   373→                }}
   374→                className="p-3 rounded-lg cursor-pointer hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated transition-colors"
   375→              >
