   380→                  {note.contentText?.slice(0, 150)}...
   381→                </div>
   382→                <div className="text-xs text-text-light-secondary dark:text-text-dark-secondary mt-1">
   383→                  {new Date(note.updatedAt).toLocaleDateString()}
