   392→          </div>
   393→        </div>
   394→      ) : (
   395→        /* Folder tree - Scrollable */
   396→        <div className="space-y-1 overflow-y-auto flex-1">
   397→          {folderTree.map((node) => (
   398→            <FolderTreeNode
   399→              key={node.id}
   400→              node={node}
   401→              depth={0}
   402→              activeFolderId={activeFolderId}
   403→              expandedFolderIds={expandedFolderIds}
   404→              onSelect={setActiveFolder}
   405→              onToggleExpanded={toggleExpanded}
   406→              onDelete={handleDeleteFolder}
   407→              onRename={handleRenameFolder}
   408→              getFolderNoteCount={getFolderNoteCount}
