   478→  // Handle PDF export with loading state
   479→  const handlePDFExport = async (e: React.MouseEvent) => {
   480→    e.stopPropagation();
   481→    setIsExporting(true);
   482→    try {
   483→      await exportNoteToPDF(note, (filename) => {
   484→        setExportSuccess(filename);
   485→        setTimeout(() => setExportSuccess(null), 3000); // Clear after 3s
   486→      });
   487→    } catch (error) {
