   633→/**
   634→ * Notes List Component
   635→ */
   636→const NotesList: React.FC<{ activeTags: string[] }> = ({ activeTags }) => {
   637→  const activeFolderId = useFoldersStore((state) => state.activeFolderId);
   638→  // Get raw notes and store config (stable references)
   639→  const notesObj = useNotesStore((state) => state.notes);
   640→  const sortConfig = useNotesStore((state) => state.sortConfig);
   641→  const filter = useNotesStore((state) => state.filter);
   642→  const activeNoteId = useNotesStore((state) => state.activeNoteId);
   643→  const createNote = useNotesStore((state) => state.createNote);
   644→
   645→  // Compute filtered/sorted notes with useMemo
   646→  const notes = useMemo(() => {
   647→    // Filter by folder
   648→    // If activeFolderId is null, show ALL notes (not just notes with null folderId)
   649→    let filtered = activeFolderId === null
   650→      ? Object.values(notesObj) // Show all notes when "All Notes" is selected
   651→      : Object.values(notesObj).filter((note) => note.folderId === activeFolderId);
   652→
   653→    // Filter by tags (AND logic - note must have ALL selected tags)
   654→    if (activeTags.length > 0) {
   655→      filtered = filtered.filter((note) =>
   656→        activeTags.every((tag) => note.tags.includes(tag))
   657→      );
   658→    }
   659→
   660→    // Apply filter (archived, pinned, favorites, etc.)
   661→    switch (filter) {
   662→      case 'favorites':
   663→        filtered = filtered.filter((note) => note.isFavorite);
   664→        break;
   665→      case 'pinned':
   666→        filtered = filtered.filter((note) => note.isPinned);
   667→        break;
   668→      case 'archived':
   669→        filtered = filtered.filter((note) => note.isArchived);
   670→        break;
   671→      case 'unarchived':
   672→        filtered = filtered.filter((note) => !note.isArchived);
   673→        break;
   674→    }
   675→
   676→    // Sort notes
   677→    const sorted = [...filtered].sort((a, b) => {
   678→      let comparison = 0;
   679→      switch (sortConfig.field) {
   680→        case 'title':
   681→          comparison = a.title.localeCompare(b.title);
   682→          break;
   683→        case 'createdAt':
   684→          comparison = a.createdAt.getTime() - b.createdAt.getTime();
   685→          break;
   686→        case 'updatedAt':
   687→          comparison = a.updatedAt.getTime() - b.updatedAt.getTime();
   688→          break;
   689→      }
   690→      return sortConfig.order === 'asc' ? comparison : -comparison;
   691→    });
   692→
   693→    // Always pin pinned notes to top
   694→    return sorted.sort((a, b) => {
   695→      if (a.isPinned && !b.isPinned) return -1;
   696→      if (!a.isPinned && b.isPinned) return 1;
   697→      return 0;
   698→    });
   699→  }, [notesObj, activeFolderId, sortConfig, filter, activeTags]);
   700→
   701→  return (
   702→    <div className="flex-1 overflow-y-auto">
   703→      <div className="bento-card p-4 m-3">
   704→        {/* Notes header */}
   705→        <div className="flex items-center justify-between mb-4">
   706→          <h3 className="font-semibold text-text-light-primary dark:text-text-dark-primary">
   707→            Notes ({notes.length})
   708→          </h3>
   709→          <button
   710→            onClick={() => createNote({ folderId: activeFolderId })}
   711→            className="px-3 py-1.5 bg-gradient-button-primary text-white rounded-lg hover:shadow-glow-magenta transition-all duration-200 text-sm font-medium"
   712→          >
   713→            + New Note
   714→          </button>
   715→        </div>
   716→
   717→      {/* Notes list */}
   718→      <div className="space-y-3">
   719→        {notes.map((note) => (
   720→          <NoteListItem
   721→            key={note.id}
   722→            note={note}
   723→            isActive={note.id === activeNoteId}
   724→          />
   725→        ))}
   726→      </div>
   727→
   728→      {/* Empty state */}
   729→      {notes.length === 0 && (
   730→        <div className="text-center py-12">
   731→          <div className="flex justify-center mb-4">
   732→            <FileText className="w-16 h-16 text-text-light-secondary dark:text-text-dark-secondary opacity-50" />
   733→          </div>
   734→          <h3 className="text-xl font-semibold text-text-light-primary dark:text-text-dark-primary mb-2">
   735→            No notes yet
   736→          </h3>
   737→          <p className="text-text-light-secondary dark:text-text-dark-secondary mb-4">
   738→            Create your first note to get started
   739→          </p>
   740→          <button
   741→            onClick={() => createNote({ folderId: activeFolderId })}
   742→            className="px-4 py-2 bg-gradient-button-primary text-white rounded-lg hover:shadow-glow-magenta transition-all duration-200 font-medium"
   743→          >
   744→            Create Note
   745→          </button>
   746→        </div>
   747→      )}
   748→      </div>
   749→    </div>
   750→  );
   751→};
   752→
   753→/**
   754→ * Notes Page Component
   755→ */
   756→export const Notes: React.FC = () => {
   757→  const activeNoteId = useNotesStore((state) => state.activeNoteId);
   758→  const dailyNotesEnabled = useSettingsStore((state) => state.dailyNotes.enabled);
   759→  const [isSidebarCollapsed, setIsSidebarCollapsed] = useState(false);
   760→  const [sidebarWidth, setSidebarWidth] = useState(320);
   761→  const [isResizing, setIsResizing] = useState(false);
   762→  const [showCalendar, setShowCalendar] = useState(false);
   763→  const sidebarRef = useRef<HTMLDivElement>(null);
   764→
   765→  // Tag filtering state
   766→  const [activeTags, setActiveTags] = useState<string[]>([]);
   767→  const [showTagManager, setShowTagManager] = useState(false);
   768→
   769→  const handleAddTag = (tag: string) => {
   770→    if (!activeTags.includes(tag)) {
   771→      setActiveTags([...activeTags, tag]);
   772→    }
   773→  };
   774→
   775→  const handleRemoveTag = (tag: string) => {
   776→    setActiveTags(activeTags.filter((t) => t !== tag));
   777→  };
   778→
   779→  const handleClearAllTags = () => {
   780→    setActiveTags([]);
   781→  };
   782→
   783→  useEffect(() => {
   784→    document.title = 'Notes - Neuman Brain';
   785→    log.debug('Notes page loaded');
   786→  }, []);
   787→
   788→  // Handle sidebar resize
   789→  const handleMouseDown = (e: React.MouseEvent) => {
   790→    e.preventDefault();
   791→    setIsResizing(true);
   792→  };
   793→
   794→  useEffect(() => {
   795→    const handleMouseMove = (e: MouseEvent) => {
   796→      if (!isResizing) return;
   797→      const newWidth = Math.max(200, Math.min(500, e.clientX - 72)); // 72px is sidebar offset
   798→      setSidebarWidth(newWidth);
   799→    };
   800→
   801→    const handleMouseUp = () => {
   802→      setIsResizing(false);
   803→    };
   804→
   805→    if (isResizing) {
   806→      document.addEventListener('mousemove', handleMouseMove);
   807→      document.addEventListener('mouseup', handleMouseUp);
   808→      document.body.style.cursor = 'ew-resize';
   809→      document.body.style.userSelect = 'none';
   810→    }
   811→
   812→    return () => {
   813→      document.removeEventListener('mousemove', handleMouseMove);
   814→      document.removeEventListener('mouseup', handleMouseUp);
   815→      document.body.style.cursor = '';
   816→      document.body.style.userSelect = '';
   817→    };
   818→  }, [isResizing]);
   819→
   820→  return (
   821→    <div className="notes-page">
   822→      {/* Page Header */}
   823→      <PageHeader />
   824→
   825→      {/* Notes Content */}
   826→      <div className="h-[calc(100vh-280px)] flex relative">
   827→        {/* Left Sidebar - Folders + Notes List */}
   828→        <AnimatePresence>
   829→        {!isSidebarCollapsed && (
   830→          <motion.div
   831→            ref={sidebarRef}
   832→            initial={{ width: 0, opacity: 0 }}
   833→            animate={{ width: sidebarWidth, opacity: 1 }}
   834→            exit={{ width: 0, opacity: 0 }}
   835→            transition={{ duration: 0.2 }}
   836→            className="flex-shrink-0 border-r border-border-light dark:border-border-dark bg-transparent flex flex-col relative"
   837→            style={{ width: sidebarWidth }}
   838→          >
   839→            <FolderSidebar
   840→              activeTags={activeTags}
   841→              onAddTag={handleAddTag}
   842→              onRemoveTag={handleRemoveTag}
   843→              onClearAllTags={handleClearAllTags}
   844→              onOpenTagManager={() => setShowTagManager(true)}
   845→            />
   846→            <NotesList activeTags={activeTags} />
   847→
   848→            {/* Collapse button - inside sidebar at top right */}
   849→            <button
   850→              onClick={() => setIsSidebarCollapsed(true)}
   851→              className="absolute top-4 right-2 z-20 p-1.5 bg-surface-light dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-button hover:bg-surface-light-elevated dark:hover:bg-neutral-800 transition-all duration-200"
   852→              title="Collapse Sidebar"
   853→            >
   854→              <svg className="w-4 h-4 text-text-light-secondary dark:text-text-dark-secondary" fill="none" stroke="currentColor" viewBox="0 0 24 24">
   855→                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 19l-7-7 7-7m8 14l-7-7 7-7" />
   856→              </svg>
   857→            </button>
   858→
   859→            {/* Resize handle */}
   860→            <div
   861→              onMouseDown={handleMouseDown}
   862→              className={`absolute right-0 top-0 bottom-0 w-1 cursor-ew-resize hover:bg-accent-blue/50 transition-colors ${isResizing ? 'bg-accent-blue' : ''}`}
   863→              title="Drag to resize"
   864→            />
   865→          </motion.div>
   866→        )}
   867→      </AnimatePresence>
   868→
   869→        {/* Sidebar expand button - shown when collapsed */}
   870→        {isSidebarCollapsed && (
   871→          <button
   872→            onClick={() => setIsSidebarCollapsed(false)}
   873→            className="flex-shrink-0 p-2 bg-surface-light dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-r-lg hover:bg-surface-light-elevated dark:hover:bg-neutral-800 transition-all duration-200 self-start mt-4 ml-2"
   874→            title="Expand Sidebar"
   875→          >
   876→            <svg className="w-4 h-4 text-text-light-secondary dark:text-text-dark-secondary" fill="none" stroke="currentColor" viewBox="0 0 24 24">
   877→              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 5l7 7-7 7M5 5l7 7-7 7" />
   878→            </svg>
   879→          </button>
   880→        )}
   881→
   882→        {/* Spacer between sidebar and editor */}
   883→        {!isSidebarCollapsed && <div className="w-4 flex-shrink-0" />}
   884→
   885→      {/* Center - Editor or Calendar */}
   886→      <div className="flex-1 overflow-hidden flex flex-col">
   887→        {/* View Toggle (only shown when no note selected and daily notes enabled) */}
   888→        {!activeNoteId && dailyNotesEnabled && (
   889→          <div className="flex gap-2 mb-4 px-4">
   890→            <button
   891→              onClick={() => setShowCalendar(false)}
   892→              className={`px-4 py-2 rounded-button text-sm font-medium transition-all ${
   893→                !showCalendar
   894→                  ? 'bg-accent-magenta dark:bg-accent-cyan text-white'
   895→                  : 'bg-surface-light-elevated dark:bg-surface-dark-elevated text-text-light-secondary dark:text-text-dark-secondary hover:bg-surface-light dark:hover:bg-surface-dark'
   896→              }`}
   897→            >
   898→              Notes
   899→            </button>
   900→            <button
   901→              onClick={() => setShowCalendar(true)}
   902→              className={`flex items-center gap-2 px-4 py-2 rounded-button text-sm font-medium transition-all ${
   903→                showCalendar
   904→                  ? 'bg-accent-magenta dark:bg-accent-cyan text-white'
   905→                  : 'bg-surface-light-elevated dark:bg-surface-dark-elevated text-text-light-secondary dark:text-text-dark-secondary hover:bg-surface-light dark:hover:bg-surface-dark'
   906→              }`}
   907→            >
   908→              <CalendarIcon className="w-4 h-4" />
   909→              Daily Notes Calendar
   910→            </button>
   911→          </div>
   912→        )}
   913→
   914→        {/* Main Content Area */}
   915→        <div className="flex-1 overflow-hidden border border-border-light dark:border-border-dark rounded-lg">
   916→          {activeNoteId ? (
   917→            <NotesEditor noteId={activeNoteId} />
   918→          ) : showCalendar && dailyNotesEnabled ? (
   919→            <div className="h-full overflow-auto p-6">
   920→              <DailyNotesCalendar />
   921→            </div>
   922→          ) : (
   923→            <NotesEditorEmpty />
   924→          )}
   925→        </div>
   926→      </div>
   927→
   928→      {/* Right Sidebar - Metadata (Future) */}
   929→      {/* TODO: Add note metadata panel */}
   930→    </div>
   931→
   932→      {/* Tag Manager Modal */}
   933→      <TagManager
   934→        isOpen={showTagManager}
   935→        onClose={() => setShowTagManager(false)}
   936→      />
   937→    </div>
   938→  );
   939→};
