importLinks: (linksData) => {
  const now = new Date();
  const newLinks: Link[] = [];

  set((state) => {
    const updatedLinks = { ...state.links };

    linksData.forEach((data) => {
      const id = generateId();
      const link: Link = {
        ...data,
        id,
        visitCount: 0,
        createdAt: now,
        updatedAt: now,
      };
      updatedLinks[id] = link;
      newLinks.push(link);
    });

    return { links: updatedLinks };
  });

  return newLinks;
},

